CREATE TABLE IF NOT EXISTS homes (id UUID PRIMARY KEY, name VARCHAR(120) NOT NULL, email VARCHAR(255) NOT NULL, budget_limit NUMERIC(12,2) NOT NULL CHECK (budget_limit > 0), base_tariff NUMERIC(12,6) NOT NULL CHECK (base_tariff >= 0), penalty_multiplier NUMERIC(8,3) NOT NULL CHECK (penalty_multiplier >= 1), created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS appliances (id UUID PRIMARY KEY, home_id UUID NOT NULL REFERENCES homes(id) ON DELETE CASCADE, name VARCHAR(120) NOT NULL, safe_watt_limit NUMERIC(12,2) NOT NULL CHECK (safe_watt_limit > 0));
CREATE TABLE IF NOT EXISTS consumption_snapshots (id BIGSERIAL PRIMARY KEY, home_id UUID NOT NULL REFERENCES homes(id) ON DELETE CASCADE, energy_kwh NUMERIC(16,6) NOT NULL, cost NUMERIC(16,4) NOT NULL, captured_at TIMESTAMPTZ NOT NULL);
CREATE INDEX IF NOT EXISTS idx_snapshots_home_time ON consumption_snapshots(home_id, captured_at);
CREATE TABLE IF NOT EXISTS audit_events (id BIGSERIAL PRIMARY KEY, home_id UUID NOT NULL REFERENCES homes(id) ON DELETE CASCADE, event_type VARCHAR(80) NOT NULL, details TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS recommendations (id BIGSERIAL PRIMARY KEY, home_id UUID NOT NULL REFERENCES homes(id) ON DELETE CASCADE, content TEXT NOT NULL, delivery_status VARCHAR(30) NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
